export default {
  provide() {
    return {
      window: this.window,
    };
  },

  data() {
    return {
      window: {
        width: 0,
      },
    };
  },

  methods: {
    handleWindowResize() {
      this.window.width = window.innerWidth;
    },
  },

  created() {
    window.addEventListener('resize', this.handleWindowResize, { passive: true });
    this.handleWindowResize();
  },

  beforeDestroy() {
    window.removeEventListener('resize', this.handleWindowResize, { passive: true });
  },
};
