/** This mixin works in tandem with @/mixins/window.js */
export default {
  computed: {
    isXs() {
      return this.window.width < 576;
    },
    isSm() {
      return 576 <= this.window.width && this.window.width < 768;
    },
    isMd() {
      return 768 <= this.window.width && this.window.width < 992;
    },
    isLg() {
      return 992 <= this.window.width && this.window.width < 1200;
    },
    isXl() {
      return this.window.width >= 1200;
    },

    isXsOnly() {
      return this.isXs;
    },
    isSmOnly() {
      return this.isSm;
    },
    isMdOnly() {
      return this.isMd;
    },
    isLgOnly() {
      return this.isLg;
    },
    isXlOnly() {
      return this.isXl;
    },

    isSmAndDown() {
      return (this.isXs || this.isSm) && !(this.isMd || this.isLg || this.isXl);
    },
    isMdAndDown() {
      return (this.isXs || this.isSm || this.isMd) && !(this.isLg || this.isXl);
    },
    isLgAndDown() {
      return (this.isXs || this.isSm || this.isMd || this.isLg) && !this.isXl;
    },

    isSmAndUp() {
      return !this.isXs && (this.isXs || this.isSm || this.isMd || this.isLg);
    },
    isMdAndUp() {
      return !(this.isXs || this.isSm) && (this.isMd || this.isLg || this.isXl);
    },
    isLgAndUp() {
      return !(this.isXs || this.isSm || this.isMd) && (this.isLg || this.isXl);
    },
  },
};
