const getInitialState = () => ({
  current: 2,
});

const getters = {
  current: (state) => state.current,
};

const actions = {};

const mutations = {
  setCurrent: function (state, v) {
    state.current = v;
  },
};

export default {
  namespaced: true,
  state: getInitialState(),
  getters,
  actions,
  mutations,
};
