<template>
  <div id="app" :class="appClass">
    <top-navigation-bar
      v-show="isMdAndUp && isAtNavbar"
      style="position: absolute; top: 0; left: 0; z-index: 100; width: 100vw;"
    />
    <router-view class="router-view" :style="routerViewStyle"/>
    <bottom-navigation-bar class="bottom-navbar-mobile" v-if="isSmAndDown"/>
  </div>
</template>

<script>
import breakpointsMixin from '@/mixins/breakpoints';
import scrollMixin from '@/mixins/scroll';
import windowMixin from '@/mixins/window';

export default {
  mixins: [
    breakpointsMixin,
    scrollMixin,
    windowMixin,
  ],

  components: {
    BottomNavigationBar: () => import('@/components/BottomNavigationBar.vue'),
    TopNavigationBar: () => import('@/components/TopNavigationBar.vue'),
  },

  computed: {
    isAtNavbar: function () {
      return this.scroll.top > this.scroll.height - this.navbarHeight;
    },

    navbarHeight: function () {
      return (this.isMdAndUp ? 3.0 : 0) * 16;
    },

    appClass: function () {
      return {
        'app-container': this.isMdAndUp,
      };
    },

    routerViewStyle: function () {
      return {
        overflow: 'auto',
        height: '100%',
        paddingBottom: '1.0rem',
      };
    },
  },

  watch: {
    isMdAndUp: function (v) {
      if (v) {
        // When resizing window width, window jumps back to page
        // 1 but the scroll hasn't detected that the window has
        // jumped. This force the scroll to detect that jump.
        this.$nextTick(() => {
          this.refreshScroll();
        });
      }
    },
  },
};

</script>

