export default {
  provide() {
    return {
      scroll: this.scroll,
    };
  },

  data() {
    return {
      scroll: {
        height: 9999999,
        top: 0,
      },
    };
  },

  methods: {
    setScrollByTarget: function (target) {
      this.scroll = {
        height: target.getBoundingClientRect().height,
        top: target.scrollTop,
      };
    },

    refreshScroll: function () {
      this.setScrollByTarget(this.getRouterViewEle());
    },

    handleScroll: function (event) {
      this.setScrollByTarget(event.target);
    },

    getRouterViewEle: function () {
      return document.getElementsByClassName('router-view')[0];
    },
  },

  mounted: function () {
    this.getRouterViewEle()
      .addEventListener('scroll', this.handleScroll, { passive: true });
  },

  beforeDestroy() {
    this.getRouterViewEle()
      .removeEventListener('scroll', this.handleScroll, { passive: true });
  },
};
